  1	import * as React from 'react';
  2	import {
  3	  Button,
  4	  ButtonVariant,
  5	  Label,
  6	  LabelGroup,
  7	  Level,
  8	  LevelItem,
  9	  Split,
 10	  SplitItem,
 11	  Stack,
 12	  StackItem,
 13	  TextContent,
 14	  Title,
 15	} from '@patternfly/react-core';
 16	import { CheckCircleIcon } from '@patternfly/react-icons/dist/esm/icons/check-circle-icon';
 17	import { debounce } from 'lodash';
 18	import { useTranslation } from 'react-i18next';
 19	import { useHistory } from 'react-router';
 20	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 21	import { getArtifactHubTaskDetails } from '../catalog/apis/artifactHub';
 22	import {
 23	  getCtaButtonText,
 24	  getTaskCtaType,
 25	  isArtifactHubTask,
 26	  isOneVersionInstalled,
 27	  isTaskVersionInstalled,
 28	  isTektonHubTaskWithoutVersions,
 29	} from './pipeline-quicksearch-utils';
 30	import PipelineQuickSearchTaskAlert from './PipelineQuickSearchTaskAlert';
 31	import PipelineQuickSearchVersionDropdown from './PipelineQuickSearchVersionDropdown';
 32	import {
 33	  getHubUIPath,
 34	  getTektonHubTaskVersions,
 35	} from '../catalog/apis/tektonHub';
 36	import { ExternalLink } from '../utils/link';
 37	import { handleCta } from '../quick-search';
 38	import { QuickSearchDetailsRendererProps } from '../quick-search/QuickSearchDetails';
 39	import { FLAGS } from '../../types';
 40	
 41	import './PipelineQuickSearchDetails.scss';
 42	
 43	const PipelineQuickSearchDetails: React.FC<QuickSearchDetailsRendererProps> = ({
 44	  selectedItem,
 45	  closeModal,
 46	  namespace,
 47	  callback,
 48	  setFailedTasks,
 49	}) => {
 50	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 51	  const history = useHistory();
 52	  const isDevConsoleProxyAvailable = useFlag(FLAGS.DEVCONSOLE_PROXY);
 53	  const [selectedVersion, setSelectedVersion] = React.useState<string>();
 54	  const [versions, setVersions] = React.useState(
 55	    selectedItem?.attributes?.versions ?? [],
 56	  );
 57	  const [hasInstalledVersion, setHasInstalledVersion] = React.useState<boolean>(
 58	    isOneVersionInstalled(selectedItem),
 59	  );
 60	  const resetVersions = React.useCallback(() => {
 61	    setVersions(selectedItem?.attributes?.versions ?? []);
 62	    setSelectedVersion(selectedItem?.attributes?.installed ?? '');
 63	    setHasInstalledVersion(isOneVersionInstalled(selectedItem));
 64	  }, [selectedItem]);
 65	
 66	  const onChangeVersion = React.useCallback(
 67	    (key) => {
 68	      setSelectedVersion(key);
 69	      if (isArtifactHubTask(selectedItem)) {
 70	        getArtifactHubTaskDetails(selectedItem, key, isDevConsoleProxyAvailable)
 71	          .then((item) => {
 72	            selectedItem.attributes.versions = item.available_versions;
 73	            selectedItem.attributes.selectedVersionContentUrl =
 74	              item.content_url;
 75	            selectedItem.tags = item.keywords;
 76	
 77	            setVersions([...item.available_versions]);
 78	            setHasInstalledVersion(isOneVersionInstalled(selectedItem));
 79	          })
 80	          .catch((err) => {
 81	            // eslint-disable-next-line no-console
 82	            console.warn('Error while getting ArtifactHub Task details:', err);
 83	            resetVersions();
 84	          });
 85	      }
 86	    },
 87	    [resetVersions, selectedItem],
 88	  );
 89	
 90	  React.useEffect(() => {
 91	    resetVersions();
 92	    const mounted = true;
 93	    if (
 94	      isTektonHubTaskWithoutVersions(selectedItem) &&
 95	      !isArtifactHubTask(selectedItem)
 96	    ) {
 97	      const debouncedLoadVersions = debounce(async () => {
 98	        if (mounted) {
 99	          try {
100	            const itemVersions = await getTektonHubTaskVersions(
101	              selectedItem?.data?.id,
102	              selectedItem?.attributes?.apiURL,
103	            );
104	
105	            selectedItem.attributes.versions = itemVersions;
106	
107	            if (mounted) {
108	              setVersions([...itemVersions]);
109	              setHasInstalledVersion(isOneVersionInstalled(selectedItem));
110	            }
111	          } catch (err) {
112	            if (mounted) {
113	              resetVersions();
114	            }
115	            console.log('failed to fetch versions:', err); // eslint-disable-line no-console
116	          }
117	        }
118	      }, 10);
119	      debouncedLoadVersions();
120	    }
121	
122	    if (isArtifactHubTask(selectedItem)) {
123	      const debouncedLoadDetails = debounce(async () => {
124	        if (mounted) {
125	          try {
126	            const item = await getArtifactHubTaskDetails(
127	              selectedItem,
128	              undefined,
129	              isDevConsoleProxyAvailable,
130	            );
131	            selectedItem.attributes.versions = item.available_versions;
132	            selectedItem.attributes.selectedVersionContentUrl =
133	              item.content_url;
134	            selectedItem.tags = item.keywords;
135	            if (mounted) {
136	              setVersions([...item.available_versions]);
137	              setHasInstalledVersion(isOneVersionInstalled(selectedItem));
138	            }
139	          } catch (err) {
140	            if (mounted) {
141	              resetVersions();
142	            }
143	          }
144	        }
145	      }, 10);
146	      debouncedLoadDetails();
147	    }
148	
149	    // return () => (mounted = false);
150	  }, [resetVersions, selectedItem]);
151	
152	  React.useEffect(() => {
153	    if (isTaskVersionInstalled(selectedItem)) {
154	      setSelectedVersion(selectedItem.attributes.installed);
155	    } else {
156	      setSelectedVersion(
157	        selectedItem.data?.latestVersion?.version?.toString() ||
158	          selectedItem.data?.task?.version?.toString(),
159	      );
160	    }
161	  }, [selectedItem]);
162	  const loadedVersion = React.useMemo(
163	    () =>
164	      versions?.find(
165	        (version) => version.version?.toString() === selectedVersion,
166	      ),
167	    [selectedVersion, versions],
168	  );
169	
170	  const hubLink = getHubUIPath(
171	    loadedVersion?.hubURLPath,
172	    selectedItem.attributes.uiURL,
173	  );
174	  return (
175	    <div className="opp-quick-search-details">
176	      <Level hasGutter>
177	        <LevelItem>
178	          <Title data-test="task-name" headingLevel="h4">
179	            {selectedItem.name}
180	          </Title>
181	        </LevelItem>
182	        <LevelItem>
183	          <Label data-test="task-provider">{selectedItem.provider}</Label>
184	        </LevelItem>
185	      </Level>
186	      <Level hasGutter>
187	        <LevelItem>
188	          <Split hasGutter>
189	            <SplitItem>
190	              <Button
191	                isDisabled={isTektonHubTaskWithoutVersions(selectedItem)}
192	                data-test="task-cta"
193	                variant={ButtonVariant.primary}
194	                className="opp-quick-search-details__form-button"
195	                onClick={(e) => {
196	                  handleCta(e, selectedItem, closeModal, history, {
197	                    selectedVersion,
198	                    selectedItem,
199	                    isDevConsoleProxyAvailable,
200	                    namespace,
201	                    callback,
202	                    setFailedTasks,
203	                  });
204	                }}
205	              >
206	                {getCtaButtonText(selectedItem, selectedVersion)}
207	              </Button>
208	            </SplitItem>
209	            {versions.length > 0 && (
210	              <SplitItem data-test="task-version-dropdown">
211	                <PipelineQuickSearchVersionDropdown
212	                  key={selectedItem.uid}
213	                  versions={versions}
214	                  item={selectedItem}
215	                  selectedVersion={selectedVersion}
216	                  onChange={onChangeVersion}
217	                />
218	              </SplitItem>
219	            )}
220	          </Split>
221	        </LevelItem>
222	        {hasInstalledVersion && (
223	          <LevelItem>
224	            <Label
225	              color="green"
226	              icon={<CheckCircleIcon />}
227	              data-test="task-installed-badge"
228	            >
229	              {t('Installed')}
230	            </Label>
231	          </LevelItem>
232	        )}
233	      </Level>
234	      {
235	        <PipelineQuickSearchTaskAlert
236	          ctaType={getTaskCtaType(selectedItem, selectedVersion)}
237	        />
238	      }
239	      <TextContent
240	        className="opp-quick-search-details__description"
241	        data-test="task-description"
242	      >
243	        {selectedItem.description}
244	        {hubLink && (
245	          <ExternalLink
246	            additionalClassName="opp-quick-search-details__hublink"
247	            dataTestID="task-hub-link"
248	            href={hubLink}
249	            text={t('Read more')}
250	          />
251	        )}
252	      </TextContent>
253	      <Stack className="opp-quick-search-details__badges-section" hasGutter>
254	        {selectedItem?.attributes?.categories?.length > 0 && (
255	          <StackItem>
256	            <LabelGroup
257	              categoryName={t('Categories')}
258	              data-test="task-category-list"
259	            >
260	              {selectedItem?.attributes?.categories.map((category) => (
261	                <Label
262	                  color="blue"
263	                  key={category}
264	                  data-test="task-category-list-item"
265	                >
266	                  {category}
267	                </Label>
268	              ))}
269	            </LabelGroup>
270	          </StackItem>
271	        )}
272	        {selectedItem?.tags?.length > 0 && (
273	          <StackItem>
274	            <LabelGroup categoryName={t('Tags')} data-test="task-tag-list">
275	              {selectedItem.tags.map((tag) => (
276	                <Label color="blue" key={tag} data-test="task-tag-list-item">
277	                  {tag}
278	                </Label>
279	              ))}
280	            </LabelGroup>
281	          </StackItem>
282	        )}
283	      </Stack>
284	    </div>
285	  );
286	};
287	
288	export default PipelineQuickSearchDetails;

