  1	import * as React from 'react';
  2	import {
  3	  render,
  4	  fireEvent,
  5	  screen,
  6	  cleanup,
  7	  waitFor,
  8	  configure,
  9	  act,
 10	} from '@testing-library/react';
 11	import { cloneDeep, omit } from 'lodash';
 12	import {
 13	  sampleTaskCatalogItem,
 14	  sampleTektonHubCatalogItem,
 15	  sampleTektonHubCatalogItemWithHubURL,
 16	} from './catalog-item-data';
 17	import PipelineQuickSearchDetails from '../PipelineQuickSearchDetails';
 18	import { consoleFetch, useFlag } from '@openshift-console/dynamic-plugin-sdk';
 19	
 20	configure({ testIdAttribute: 'data-test' });
 21	
 22	const coFetchMock = consoleFetch as jest.Mock;
 23	const useFlagMock = useFlag as jest.Mock;
 24	
 25	jest.mock('@openshift-console/dynamic-plugin-sdk', () => ({
 26	  consoleFetch: jest.fn(),
 27	  useFlag: jest.fn(),
 28	}));
 29	
 30	jest.mock('@console/shared/src/hooks/useTelemetry', () => ({
 31	  useTelemetry: () => {},
 32	}));
 33	
 34	// FIXME Remove this code when jest is updated to at least 25.1.0 -- see https://github.com/jsdom/jsdom/issues/1555
 35	if (!Element.prototype.closest) {
 36	  Element.prototype.closest = function (this: Element, selector: string) {
 37	    // eslint-disable-next-line @typescript-eslint/no-this-alias
 38	    let el: Element | null = this;
 39	    while (el) {
 40	      if (el.matches(selector)) return el;
 41	      el = el.parentElement;
 42	    }
 43	    return null;
 44	  };
 45	}
 46	
 47	beforeEach(() => {
 48	  coFetchMock.mockClear();
 49	  coFetchMock.mockReturnValue(
 50	    Promise.resolve({
 51	      json: () => ({
 52	        data: {
 53	          versions: sampleTektonHubCatalogItem.attributes.versions,
 54	        },
 55	      }),
 56	    }),
 57	  );
 58	  useFlagMock.mockReturnValue(true);
 59	});
 60	
 61	describe('pipelineQuickSearchDetails', () => {
 62	  const taskProps = {
 63	    selectedItem: sampleTaskCatalogItem,
 64	    closeModal: jest.fn(),
 65	  };
 66	
 67	  const tektonHubProps = {
 68	    selectedItem: sampleTektonHubCatalogItem,
 69	    closeModal: jest.fn(),
 70	  };
 71	
 72	  afterEach(() => cleanup());
 73	
 74	  describe('Installed badge tests', () => {
 75	    it('should show the installed badge for the cluster task', async () => {
 76	      const { queryByTestId } = render(
 77	        <PipelineQuickSearchDetails {...taskProps} />,
 78	      );
 79	      await waitFor(() => {
 80	        expect(queryByTestId('task-installed-badge')).not.toBeNull();
 81	      });
 82	    });
 83	
 84	    it('should show the installed badge for the installed tekton hub task', async () => {
 85	      const installedTektonHubTask = {
 86	        ...sampleTektonHubCatalogItem,
 87	        attributes: {
 88	          ...sampleTektonHubCatalogItem.attributes,
 89	          installed: '0.1',
 90	        },
 91	      };
 92	      const { queryByTestId } = render(
 93	        <PipelineQuickSearchDetails
 94	          {...tektonHubProps}
 95	          selectedItem={installedTektonHubTask}
 96	        />,
 97	      );
 98	      await waitFor(() => {
 99	        expect(queryByTestId('task-installed-badge')).not.toBeNull();
100	      });
101	    });
102	
103	    it('should not show the installed badge for the uninstalled tekton hub task', async () => {
104	      const { queryByTestId } = render(
105	        <PipelineQuickSearchDetails {...tektonHubProps} />,
106	      );
107	      await waitFor(() => {
108	        expect(queryByTestId('task-installed-badge')).toBeNull();
109	      });
110	    });
111	  });
112	
113	  describe('CTA button tests', () => {
114	    it('Add button should be disabled if the versions is not available', async () => {
115	      const taskWithoutVersion = cloneDeep({ ...tektonHubProps.selectedItem });
116	      taskWithoutVersion.attributes.versions = [];
117	      coFetchMock.mockReturnValue(
118	        Promise.resolve({
119	          json: () => ({
120	            data: {
121	              versions: [],
122	            },
123	          }),
124	        }),
125	      );
126	      const { getByRole } = render(
127	        <PipelineQuickSearchDetails
128	          {...tektonHubProps}
129	          selectedItem={taskWithoutVersion}
130	        />,
131	      );
132	      await waitFor(() => {
133	        expect(
134	          getByRole('button', { name: 'Install and add' }).getAttribute(
135	            'aria-disabled',
136	          ),
137	        ).toBe('true');
138	      });
139	    });
